  updateExploration(episode: number) {
    // Decay epsilon over time
    this.epsilon = Math.max(
      this.epsilonMin,
      this.epsilon * this.epsilonDecay
    );

    // Optional: Boltzmann exploration for smoother transitions
    this.temperature = Math.max(0.1, this.temperature * 0.99);
  }

  selectActionBoltzmann(qValues: number[]): number {
    // Softmax probability distribution
    const expValues = qValues.map(q => Math.exp(q / this.temperature));
    const sumExp = expValues.reduce((a, b) => a + b, 0);
    const probabilities = expValues.map(e => e / sumExp);

    // Sample from distribution
    const random = Math.random();
    let cumSum = 0;
    for (let i = 0; i < probabilities.length; i++) {
      cumSum += probabilities[i];
      if (random < cumSum) return i;
    }
    return probabilities.length - 1;
  }
