  if (isGoalReached(nextState)) {
    reward += 100; // Large positive reward
    return reward;
  }

  // 2. Collision Penalty
  if (hasCollided(nextState)) {
    reward -= 50; // Large negative penalty
    return reward;
  }

  // 3. Distance-based Shaping (Potential Function)
  const prevDist = distanceToGoal(state);
  const currDist = distanceToGoal(nextState);
  const distanceReward = (prevDist - currDist) * 10; // Encourage moving toward goal
  reward += distanceReward;

  // 4. Step Penalty (Encourage Efficiency)
  reward -= 0.1; // Small penalty for each step

  // 5. Exploration Bonus (Optional)
  if (isUnvisitedState(nextState)) {
    reward += 0.5; // Small bonus for discovering new states
  }

